class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        total = sum(nums)
        if total % k:
            return False
        target = total // k
        nums.sort(reverse=True)
        if nums[0] > target:
            return False
        visited = [False] * len(nums)
        return self.dfs(nums, k, target, 0, visited)

    def dfs(self, nums, k, target, pos, visited):
        if pos == len(nums):
            return True
        for i in range(pos, len(nums)):
            if not visited[i]:
                if target - nums[i] < 0:
                    return False
                if not self.dfs(nums, k, target - nums[i], i + 1, visited | {i}):
                    return False
                visited[i] = True
                if self.dfs(nums, k, target, i + 1, visited):
                    return True
                visited[i] = False
        return False
